import React from 'react';

const TABS = ['Home', 'About', 'Global Friends', 'Resources', 'Contact'];

export default function Footer() {
  return (
    <footer style={{ background: '#454545', padding: '68px 52px 32px' }}>
      <div style={{ maxWidth: 1100, margin: '0 auto' }}>

        <div style={{
          display: 'grid', gridTemplateColumns: '1fr 2fr 1fr',
          gap: 48, marginBottom: 52, alignItems: 'start',
        }}>

          {/* Logo + tagline */}
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 14 }}>
              <div style={{
                width: 40, height: 40, borderRadius: '50%', background: 'white',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontWeight: 900, fontSize: 14,
              }}>
                <span style={{ color: '#fa824c' }}>G</span>
                <span style={{ color: '#2d80f2' }}>F</span>
              </div>
              <span style={{ color: 'white', fontWeight: 800, fontSize: 16 }}>Global Friends</span>
            </div>
            <p style={{ color: '#b5b5b5', fontSize: '.9rem', lineHeight: 1.75, fontWeight: 500 }}>
              Building community for internationals across Colorado.
            </p>
          </div>

          {/* Nav links */}
          <div style={{
            display: 'flex', justifyContent: 'center',
            gap: 28, flexWrap: 'wrap', paddingTop: 6,
          }}>
            {TABS.map(tab => (
              <a key={tab} href="#" style={{
                color: '#b5b5b5', textDecoration: 'none',
                fontWeight: 700, fontSize: 14,
                transition: 'color .2s ease',
              }}
                onMouseEnter={e => (e.currentTarget.style.color = 'white')}
                onMouseLeave={e => (e.currentTarget.style.color = '#b5b5b5')}
              >
                {tab}
              </a>
            ))}
          </div>

          {/* Contact */}
          <div style={{ textAlign: 'right' }}>
            <p style={{ color: 'white', fontWeight: 800, fontSize: '1rem', marginBottom: 14 }}>
              Contact Us
            </p>
            <p style={{ color: '#b5b5b5', fontSize: '.9rem', fontWeight: 500, lineHeight: 2 }}>
              📧 hello@globalfriends.co<br />
              📍 Colorado, USA<br />
              📱 (720) 555-0199
            </p>
          </div>

        </div>

        <div style={{
          borderTop: '1px solid rgba(255,255,255,.1)',
          paddingTop: 24, textAlign: 'center',
          color: '#b5b5b5', fontSize: '.875rem', fontWeight: 600,
        }}>
          © 2025 Global Friends Colorado. Made with ❤️ for internationals.
        </div>

      </div>
    </footer>
  );
}
